{"command": "cd /tmp/sv-415162e54a0d426ea244c98602899cc8

# Also cross-check with nm to find the actual function at those addresses
# For the SGen worker addresses (0x2f4b20, 0x2f4c84) and Finalizer (0x2c1a40)
nm -C libmonosgen-2.0.so.dbg 2>/dev/null | sort | awk -v a1=0x2f4b20 -v a2=0x2f4c84 -v a3=0x2c1a40 '
  /^[0-9a-f]+ [tTwW]/ { addr="0x"$1; name=$3; addrs[addr]=name; sorted[NR]=addr }
' | head -5

# More targeted: find functions containing those addresses
for addr in 0x2f4b20 0x2f4c84 0x2c1a40; do
  echo "=== $addr ==="
  nm libmonosgen-2.0.so.dbg 2>/dev/null | awk -v target="$addr" '
    $2 ~ /[tTwW]/ {
      a = strtonum("0x"$1)
      t = strtonum(target)
      if (a <= t && (best == 0 || a > best)) { best = a; name = $3 }
    }
    END { printf "  %s + 0x%x\n", name, strtonum(target) - best }
  '
done", "description": "Cross-check function names via nm"}

