cd /tmp/sv-415162e54a0d426ea244c98602899cc8

# Check the actual binary's section layout
readelf -SW libmonosgen-2.0.so 2>/dev/null | grep -E '(\.text|\.plt|\.data|\.rodata|Nr|Name)' | head -20

echo ""
echo "=== Checking if SGen addresses are in executable sections ==="
readelf -SW libmonosgen-2.0.so 2>/dev/null | awk '
  /PROGBITS/ || /NOBITS/ {
    name = $2
    addr = strtonum("0x"$4)
    off = strtonum("0x"$5)
    size = strtonum("0x"$6)
    flags = ""
    for (i=7; i<=NF; i++) { if ($i ~ /^[WAXMSIL]+$/) flags = $i }
    for (target_hex in targets) {
      t = strtonum(target_hex)
      if (t >= addr && t < addr + size) {
        printf "  0x%x is in section %s (0x%x-0x%x, flags=%s)\n", t, name, addr, addr+size, flags
      }
    }
  }
  BEGIN {
    targets["0x2f4b20"] = 1
    targets["0x2f4c84"] = 1
    targets["0x222098"] = 1
    targets["0x16de04"] = 1
    targets["0x2c1a40"] = 1
