  $4 == "FUNC" && $8 !~ /^\$/ && $8 !~ /^__CortexA53/ {
    addr = strtonum("0x"$2)
    size = strtonum($3)
    end = addr + size
    # Check SGen worker addresses
    if (0x2f4b20 >= addr && 0x2f4b20 < end) {
      printf "0x2f4b20 in %s (0x%x + 0x%x, size=%d)\n", $8, addr, 0x2f4b20 - addr, size
    }
    if (0x2f4c84 >= addr && 0x2f4c84 < end) {
      printf "0x2f4c84 in %s (0x%x + 0x%x, size=%d)\n", $8, addr, 0x2f4c84 - addr, size
